// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('validate column ウエイト', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('validate column ウエイト', async function() {
    // Test name: validate column ウエイト
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-8-10/5 | 
    await driver.get("http://localhost:4200/user/evaluation-8-10/5");

    // 2 | waitForElementPresent | xpath=//div[@id='rc-tabs-1-panel-1']/form/button | 2000
    await driver.wait(until.elementLocated(By.xpath("//div[@id=\'rc-tabs-1-panel-1\']/form/button")), 2000);

    // 3 | click | xpath=//span[contains(.,'追 加')] | 
    await driver.findElement(By.xpath("//span[contains(.,\'追 加\')]")).click();

    // 4 | click | xpath=//div[@id='rc-tabs-1-panel-1']/form/button/span | 
    await driver.findElement(By.xpath("//div[@id=\'rc-tabs-1-panel-1\']/form/button/span")).click();

    // 5 | click | id=weight_1 | 
    await driver.findElement(By.id("weight_1")).click();

    // 6 | click | id=weight_1 | 
    await driver.findElement(By.id("weight_1")).click();

    // 7 | type | id=weight_1 | 111
    await driver.findElement(By.id("weight_1")).sendKeys("111");

    // 8 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 9 | verifyText | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "vui long nhap trong khoang 1 den 100");

    // 10 | click | id=weight_1 | 
    await driver.findElement(By.id("weight_1")).click();

    // 11 | type | id=weight_1 |  
    await driver.findElement(By.id("weight_1")).sendKeys(" ");

    // 12 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 13 | verifyText | css=.ant-form-item-explain-error | ko de trong
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "ko de trong");

    // 14 | click | id=weight_1 | 
    await driver.findElement(By.id("weight_1")).click();

    // 15 | click | id=weight_1 | 
    await driver.findElement(By.id("weight_1")).click();

    // 16 | type | id=weight_1 | aaa
    await driver.findElement(By.id("weight_1")).sendKeys("aaa");

    // 17 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 18 | verifyText | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "vui long nhap trong khoang 1 den 100");

    // 19 | doubleClick | id=weight_1 | 
    {
      const element = await driver.findElement(By.id("weight_1"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 20 | type | id=weight_1 | 11@
    await driver.findElement(By.id("weight_1")).sendKeys("11@");

    // 21 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 22 | verifyText | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "vui long nhap trong khoang 1 den 100");

    // 23 | doubleClick | id=weight_1 | 
    {
      const element = await driver.findElement(By.id("weight_1"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 24 | type | id=weight_1 | ...
    await driver.findElement(By.id("weight_1")).sendKeys("...");

    // 25 | click | css=.ant-form-item-explain-error | 
    await driver.findElement(By.css(".ant-form-item-explain-error")).click();

    // 26 | verifyText | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    assert(await driver.findElement(By.css(".ant-form-item-explain-error")).getText() == "vui long nhap trong khoang 1 den 100");

    // 27 | click | id=weight_1 | 
    await driver.findElement(By.id("weight_1")).click();

    // 28 | doubleClick | id=weight_1 | 
    {
      const element = await driver.findElement(By.id("weight_1"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 29 | type | id=weight_1 | 1
    await driver.findElement(By.id("weight_1")).sendKeys("1");

    // 30 | waitForElementNotPresent | css=.ant-form-item-explain-error | 2000
    await driver.wait(until.stalenessOf(await driver.findElement(By.css(".ant-form-item-explain-error"))), 2000);

    // 31 | verifyElementNotPresent | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    {
      const elements = await driver.findElements(By.css(".ant-form-item-explain-error"));
      assert(!elements.length);
    }

    // 32 | doubleClick | id=weight_1 | 
    {
      const element = await driver.findElement(By.id("weight_1"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 33 | type | id=weight_1 | 100
    await driver.findElement(By.id("weight_1")).sendKeys("100");

    // 34 | verifyElementNotPresent | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    {
      const elements = await driver.findElements(By.css(".ant-form-item-explain-error"));
      assert(!elements.length);
    }

    // 35 | doubleClick | id=weight_1 | 
    {
      const element = await driver.findElement(By.id("weight_1"));
      await driver.actions({ bridge: true}).doubleClick(element).perform();
    }

    // 36 | type | id=weight_1 | 99
    await driver.findElement(By.id("weight_1")).sendKeys("99");

    // 37 | verifyElementNotPresent | css=.ant-form-item-explain-error | vui long nhap trong khoang 1 den 100
    {
      const elements = await driver.findElements(By.css(".ant-form-item-explain-error"));
      assert(!elements.length);
    }
  });
});
